'use strict';

const { allProducts } = require('../core/products.js');
const { allOrders, orderTotal } = require('../core/orders.js');
const { customerById } = require('../core/customers.js');

function summaryReport() {
  const products = allProducts();
  const orders = allOrders();

  const productCount = products.length;
  const orderCount = orders.length;

  let totalRevenue = 0;
  const customerRevenue = {};

  for (const order of orders) {
    const total = orderTotal(order);
    totalRevenue += total;
    customerRevenue[order.customerId] = (customerRevenue[order.customerId] || 0) + total;
  }

  let topCustomerId = null;
  let topRevenue = 0;
  for (const [customerId, revenue] of Object.entries(customerRevenue)) {
    if (revenue > topRevenue) {
      topRevenue = revenue;
      topCustomerId = customerId;
    }
  }

  const topCustomer = topCustomerId ? customerById(topCustomerId) : null;

  return [
    `products: ${productCount}`,
    `orders: ${orderCount}`,
    `revenue: $${totalRevenue.toFixed(2)}`,
    `top-customer: ${topCustomer ? topCustomer.name : 'none'} ($${topRevenue.toFixed(2)})`,
  ];
}

module.exports = { summaryReport };

